// Import the useState and useMemo hooks
import { useState, useMemo } from 'react';

// Define a function component
function MyComponent({ name, age }) {
  // Use the useState hook to create a state variable
  const [count, setCount] = useState(0);

  // Use the useMemo hook to memoize a value
  const memoizedValue = useMemo(() => {
    // Recalculate the value on every render
    return `Name: ${name}, Age: ${age}`;
  }, []);

  // Return a JSX element
  return (
    <div>
      {memoizedValue}
      <button onClick={() => setCount(count + 1)}>Increment Count</button>
    </div>
  );
}

// Export the function component
export default MyComponent;

